package com.chaobo.scm.supplier.application.finance;

import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.infrastructure.persistence.finance.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.math.*;
@Service public class SupplierFinanceLifecycleApplicationService {private final SupplierFinanceMapper finance;private final SupplierFinanceLifecycleMapper lifecycle;private final AuditLogRepository audit;public SupplierFinanceLifecycleApplicationService(SupplierFinanceMapper finance,SupplierFinanceLifecycleMapper lifecycle,AuditLogRepository audit){this.finance=finance;this.lifecycle=lifecycle;this.audit=audit;}@Transactional public void resolveDifference(long id,int version,BigDecimal amount,String resolution,CommandContext c){c.requirePermission("supplier:reconciliation:resolve");var row=reconciliation(id);c.requireSupplierScope(row.supplierId());validAmount(amount);if(resolution==null||resolution.isBlank())throw rule("差异处理结论不能为空");if(lifecycle.resolveDifference(id,version,amount,resolution.trim())!=1)throw conflict();audit.save(c,"RESOLVE_RECONCILIATION_DIFFERENCE","RECONCILIATION",id,row.statementNo(),null,"{\"status\":2}");}@Transactional public void closeReconciliation(long id,int version,CommandContext c){c.requirePermission("supplier:reconciliation:close");var row=reconciliation(id);c.requireSupplierScope(row.supplierId());if(lifecycle.close(id,version)!=1)throw conflict();audit.save(c,"CLOSE_RECONCILIATION","RECONCILIATION",id,row.statementNo(),null,"{\"status\":5}");}@Transactional public void closeFromBms(String no,long supplierId,int sourceVersion){if(no==null||no.isBlank()||supplierId<=0)throw rule("BMS 对账关闭数据不合法");lifecycle.closeFromBms(no,supplierId,sourceVersion);}@Transactional public void resubmitInvoice(long id,int version,BigDecimal net,BigDecimal tax,BigDecimal rate,String url,CommandContext c){c.requirePermission("supplier:invoice:resubmit");var row=invoice(id);c.requireSupplierScope(row.supplierId());validInvoice(net,tax,rate,url);if(lifecycle.resubmitInvoice(id,version,net,tax,rate,url)!=1)throw conflict();audit.save(c,"RESUBMIT_INVOICE","INVOICE",id,row.invoiceNo(),null,"{\"status\":1}");}@Transactional public void closeInvoice(long id,int version,CommandContext c){c.requirePermission("supplier:invoice:close");var row=invoice(id);c.requireSupplierScope(row.supplierId());if(lifecycle.closeInvoice(id,version)!=1)throw conflict();audit.save(c,"CLOSE_INVOICE","INVOICE",id,row.invoiceNo(),null,"{\"status\":4}");}private FinanceViews.Reconciliation reconciliation(long id){var r=finance.reconciliation(id);if(r==null)throw new BusinessException(ErrorCode.NOT_FOUND,"对账单不存在");return r;}private FinanceViews.Invoice invoice(long id){var r=finance.invoice(id);if(r==null)throw new BusinessException(ErrorCode.NOT_FOUND,"发票不存在");return r;}private static void validAmount(BigDecimal value){if(value==null||value.signum()<0)throw rule("金额不合法");}private static void validInvoice(BigDecimal net,BigDecimal tax,BigDecimal rate,String url){validAmount(net);validAmount(tax);if(rate==null||rate.signum()<0||url==null||url.isBlank())throw rule("发票数据不合法");if(net.multiply(rate).setScale(2,RoundingMode.HALF_UP).compareTo(tax.setScale(2,RoundingMode.HALF_UP))!=0)throw rule("税额与不含税金额、税率不匹配");}private static BusinessException rule(String m){return new BusinessException(ErrorCode.BUSINESS_RULE_FAILED,m);}private static BusinessException conflict(){return new BusinessException(ErrorCode.VERSION_CONFLICT,"状态或版本已变更");}}
